import { blockId } from './flow-id.js';

const PAGE_BREAK_COMMENT_RE = /\s*(page-break-before|break-before)\s*/i;

// Node type constants (avoids relying on the global Node in non-DOM contexts).
const ELEMENT_NODE = 1;
const TEXT_NODE = 3;
const COMMENT_NODE = 8;

function escapeHtml(text) {
  return String(text ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

/**
 * Best-effort, dependency-free HTML sanitizer.
 *
 * Strips <script>/<style> elements, inline event-handler attributes (on*),
 * and javascript: URLs. This is intentionally lightweight so the library stays
 * renderer-free and adds no bundle weight. For untrusted input, pass a stronger
 * sanitizer (e.g. DOMPurify.sanitize) via FlowDocument's `sanitize` prop.
 */
export function sanitizeHtml(html) {
  return String(html ?? '')
    // Remove <script>/<style> blocks including their contents.
    .replace(/<(script|style)\b[^>]*>[\s\S]*?<\/\1\s*>/gi, '')
    // Remove any dangling/unclosed <script>/<style> open tags.
    .replace(/<\/?(script|style)\b[^>]*>/gi, '')
    // Remove inline event handlers: onclick="...", onload='...', onerror=foo
    .replace(/\son\w+\s*=\s*"[^"]*"/gi, '')
    .replace(/\son\w+\s*=\s*'[^']*'/gi, '')
    .replace(/\son\w+\s*=\s*[^\s>]+/gi, '')
    // Remove javascript: URLs in href/src/xlink:href.
    .replace(/\s(href|src|xlink:href)\s*=\s*"javascript:[^"]*"/gi, '')
    .replace(/\s(href|src|xlink:href)\s*=\s*'javascript:[^']*'/gi, '');
}

/**
 * Parse an HTML string into flat block tokens using the browser's native parser.
 *
 * Each top-level element becomes an `element` token; significant top-level text
 * becomes a `text` token; recognized page-break comments become `break` tokens.
 * Returns [] when no DOM is available (SSR / tests inject `parseHtml` instead).
 */
function parseHtmlToTokens(html, breakComment) {
  if (typeof document === 'undefined') return [];

  const template = document.createElement('template');
  template.innerHTML = String(html ?? '');

  const tokens = [];

  template.content.childNodes.forEach((node) => {
    if (node.nodeType === COMMENT_NODE) {
      if (breakComment.test(node.textContent ?? '')) {
        tokens.push({ kind: 'break' });
      }
      return;
    }

    if (node.nodeType === TEXT_NODE) {
      const text = (node.textContent ?? '').trim();
      if (text) tokens.push({ kind: 'text', html: escapeHtml(text), text });
      return;
    }

    if (node.nodeType === ELEMENT_NODE) {
      const element = node;
      const breakBefore = element.hasAttribute('data-flow-break-before');
      const breakAfter = element.hasAttribute('data-flow-break-after');
      // The break markers are control hints, not output; strip them so they do
      // not leak into the rendered item html.
      element.removeAttribute('data-flow-break-before');
      element.removeAttribute('data-flow-break-after');

      tokens.push({
        kind: 'element',
        type: element.tagName.toLowerCase(),
        html: element.outerHTML,
        text: element.textContent ?? '',
        breakBefore,
        breakAfter,
      });
    }
  });

  return tokens;
}

function tokensToItems(tokens, options) {
  const idPrefix = options.idPrefix ?? '';
  const items = [];
  let breakBeforeNext = false;

  for (const token of tokens) {
    if (!token || token.kind === 'break') {
      breakBeforeNext = true;
      continue;
    }

    const type = token.type ?? 'text';
    const html = token.html ?? '';
    if (!html) continue;

    items.push({
      id: blockId(type, token.text ?? html, items.length, idPrefix),
      type,
      html,
      breakBefore: breakBeforeNext || Boolean(token.breakBefore),
    });

    // A break-after on this element is expressed as a break-before on the next
    // item, so the item shape stays parallel to markdownToFlowItems.
    breakBeforeNext = Boolean(token.breakAfter);
  }

  return items;
}

/**
 * Convert an HTML string into explicit Static.Flow items.
 *
 * Mirrors markdownToFlowItems: top-level blocks become items the flow algorithm
 * can move between pages. Splitting is block-level only — a single oversized
 * element (huge table, long list) is one item and will not split line-by-line.
 *
 * @param {string} html
 * @param {{ idPrefix?: string, breakComment?: RegExp, parseHtml?: (html: string) => Array }} [options]
 * @returns {Array<{ id: string, type: string, html: string, breakBefore: boolean }>}
 */
export function htmlToFlowItems(html = '', options = {}) {
  const breakComment = options.breakComment ?? PAGE_BREAK_COMMENT_RE;
  const parse = options.parseHtml ?? ((source) => parseHtmlToTokens(source, breakComment));
  const tokens = parse(html);
  return tokensToItems(Array.isArray(tokens) ? tokens : [], options);
}
