import * as React from 'react';
import { isDev } from '../utility/is-dev';
import { distributeFlowItems, getFlowFragmentState } from './flow-core';

export type StaticFlowItemMeta = {
  breakBefore?: boolean;
  breakAfter?: boolean;
  keepWithNext?: boolean | number;
  avoidBreakInside?: boolean;
  groupKey?: string;
};

export type StaticFlowItemGroup = {
  /** A stable key for the repeatable header group. */
  key: string;
  /** Repeat the group header if this group resumes on a later virtual page. */
  repeatHeader?: boolean;
};

export type StaticFlowFragmentContext<TItem = unknown> = {
  flowId: string;
  pageIndex: number;
  pageCount: number;
  itemIndex: number;
  itemKey: React.Key;
  item: TItem;
  groupKey?: string;
  isFirst: boolean;
  isLast: boolean;
  isFirstInFragment: boolean;
  isLastInFragment: boolean;
  isFirstInGroup: boolean;
  isFirstInGroupOnPage: boolean;
  /** This item is on a virtual continuation page of the Flow. */
  isContinuation: boolean;
  /** This group resumes from the preceding virtual page. */
  isGroupContinuation: boolean;
};

export type StaticFlowUnplaceableItem = {
  index: number;
  key: string;
  height: number;
  headerHeight: number;
  requiredHeight: number;
  availableHeight: number;
  groupKey?: string;
  reason: 'item-too-tall' | 'item-with-header-too-tall';
};

export type StaticFlowUnplaceableContext = {
  flowId: string;
  pageIndex: number;
  pageCount: number;
};

export type StaticFlowGroupHeaderFragment = {
  groupKey: string;
  itemIndex: number;
  isContinuation: boolean;
};

export type StaticFlowChunk = {
  indexes: number[];
  keys: string[];
  /** Header insertion points for this exact measured virtual-page fragment. */
  groupHeaders?: StaticFlowGroupHeaderFragment[];
  /** A finite, renderable error page for a row that cannot fit on an empty page. */
  unplaceable?: StaticFlowUnplaceableItem;
};

export type StaticFlowMeasurement = {
  flowId: string;
  chunks: StaticFlowChunk[];
  signature: string;
  unplaceableItems?: StaticFlowUnplaceableItem[];
};

export type StaticFlowContextValue = {
  mode: 'measure' | 'visible';
  pageIndex: number;
  measurementVersion?: string;
  chunksByFlowId?: Record<string, StaticFlowChunk[]>;
  registerMeasurement?: (measurement: StaticFlowMeasurement) => void;
};

export const StaticFlowContext = React.createContext<StaticFlowContextValue | null>(null);

type FlowAreaProps = {
  children: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
  /** Receives the same measured plan that drives virtual continuation pages. */
  onFlowMeasurement?: (measurement: StaticFlowMeasurement) => void;
};

const useIsoLayoutEffect = typeof window === 'undefined' ? React.useEffect : React.useLayoutEffect;
const warnedMetaDefaultsWithoutType = new Set<string>();

type FlowItemType<TItem> = TItem extends { type?: infer TType }
  ? Extract<TType, string>
  : string;

type DefaultFlowItemType<TItem> = [FlowItemType<TItem>] extends [never]
  ? string
  : FlowItemType<TItem>;

function getItemType(item: unknown): string | undefined {
  if (!item || typeof item !== 'object' || !('type' in item)) return undefined;
  const type = (item as { type?: unknown }).type;
  return typeof type === 'string' || typeof type === 'number' ? String(type) : undefined;
}

function mergeItemMeta(
  base: StaticFlowItemMeta | undefined,
  override: StaticFlowItemMeta | undefined
): StaticFlowItemMeta {
  const merged: StaticFlowItemMeta = { ...(base ?? {}) };

  for (const [key, value] of Object.entries(override ?? {})) {
    if (value !== undefined) {
      (merged as Record<string, unknown>)[key] = value;
    }
  }

  return merged;
}

function parseKeepWithNext(value: string | undefined): boolean | number {
  if (!value) return false;
  if (value === 'true') return true;

  const count = Number.parseInt(value, 10);
  return Number.isFinite(count) && count > 0 ? count : false;
}

function serializeKeepWithNext(value: StaticFlowItemMeta['keepWithNext']): string | undefined {
  if (typeof value === 'number' && Number.isFinite(value) && value > 0) {
    return String(Math.floor(value));
  }

  return value ? 'true' : undefined;
}

// Compact, allocation-light FNV-1a hash. The signature is only used as an opaque
// change-detection token (equality compare), so a short hash beats embedding the
// full inputs + derived chunks as JSON.
function hashString(value: string): string {
  let hash = 0x811c9dc5;
  for (let index = 0; index < value.length; index += 1) {
    hash ^= value.charCodeAt(index);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(36);
}

/**
 * The product of every ancestor CSS transform (preview fit-to-pane, host zoom), derived at read
 * time: offsetWidth is layout-space while the rect is visual-space. Chunking must run in layout
 * space — rects scale under a transform but computed margins do not, so an un-normalized
 * measurement pass silently paginates differently in a scaled preview than in the real document.
 */
function getEffectiveScale(element: HTMLElement): number {
  const rectWidth = element.getBoundingClientRect().width;
  const layoutWidth = element.offsetWidth;
  if (!(rectWidth > 0) || !(layoutWidth > 0)) return 1;
  const scale = rectWidth / layoutWidth;
  // offsetWidth is integer-rounded; treat near-1 ratios as the untransformed common case.
  return Math.abs(scale - 1) < 0.002 ? 1 : scale;
}

function getOuterHeight(element: HTMLElement, scale = 1): number {
  const rect = element.getBoundingClientRect();
  const styles = window.getComputedStyle(element);
  const marginTop = Number.parseFloat(styles.marginTop || '0') || 0;
  const marginBottom = Number.parseFloat(styles.marginBottom || '0') || 0;
  return rect.height / scale + marginTop + marginBottom;
}

function readItemMeta(element: HTMLElement): StaticFlowItemMeta {
  return {
    breakBefore: element.dataset.uhuuFlowBreakBefore === 'true',
    breakAfter: element.dataset.uhuuFlowBreakAfter === 'true',
    keepWithNext: parseKeepWithNext(element.dataset.uhuuFlowKeepWithNext),
    avoidBreakInside: element.dataset.uhuuFlowAvoidBreakInside === 'true',
    groupKey: element.dataset.uhuuFlowGroupKey,
  };
}

function readHeaderGroupKey(element: HTMLElement): string | undefined {
  const value = element.dataset.uhuuFlowHeaderGroupKey;
  return value || undefined;
}

function readHeaderGroupRepeats(itemElements: HTMLElement[]): Record<string, boolean> {
  const repeats: Record<string, boolean> = {};

  for (const item of itemElements) {
    const groupKey = readHeaderGroupKey(item);
    if (!groupKey) continue;
    if (item.dataset.uhuuFlowHeaderRepeat === 'false') {
      repeats[groupKey] = false;
    } else if (!(groupKey in repeats)) {
      repeats[groupKey] = true;
    }
  }

  return repeats;
}

function readHeaderGroupHeights(flow: HTMLElement, scale = 1): Record<string, number> {
  const heights: Record<string, number> = {};

  for (const header of Array.from(
    flow.querySelectorAll<HTMLElement>('[data-uhuu-flow-group-header="true"]')
  )) {
    const groupKey = header.dataset.uhuuFlowHeaderGroupKey;
    if (!groupKey) continue;
    // A header can occur more than once in a measurement render when a group
    // is non-contiguous. Use the largest observed variant to avoid clipping.
    heights[groupKey] = Math.max(heights[groupKey] ?? 0, getOuterHeight(header, scale));
  }

  return heights;
}

type BuildChunksOptions = {
  onZeroHeight?: () => void;
  onUnplaceableItem?: (item: StaticFlowUnplaceableItem) => void;
};

function buildChunks(
  area: HTMLElement,
  flow: HTMLElement,
  options: BuildChunksOptions = {}
): StaticFlowMeasurement | null {
  const flowId = flow.dataset.uhuuFlowId;
  if (!flowId) return null;

  const itemElements = Array.from(flow.querySelectorAll<HTMLElement>('[data-uhuu-flow-item="true"]'));
  if (!itemElements.length) {
    return {
      flowId,
      chunks: [{ indexes: [], keys: [] }],
      signature: `${flowId}:empty`,
      unplaceableItems: [],
    };
  }

  const areaRect = area.getBoundingClientRect();
  // Normalize every rect read back to layout space so a scaled preview (fit-to-pane, host zoom)
  // measures the exact same chunk plan as the unscaled published document.
  const scale = getEffectiveScale(area);
  const measuredAvailableHeight = areaRect.height ? areaRect.height / scale : area.clientHeight;
  const hasAvailableHeight = Number.isFinite(measuredAvailableHeight) && measuredAvailableHeight > 0;
  const heights = itemElements.map((item) => getOuterHeight(item, scale));
  const metas = itemElements.map(readItemMeta);
  const keys = itemElements.map((item, index) => item.dataset.uhuuFlowKey || String(index));
  const headerGroupKeys = itemElements.map(readHeaderGroupKey);
  const headerGroupRepeats = readHeaderGroupRepeats(itemElements);
  const headerGroupHeights = readHeaderGroupHeights(flow, scale);
  const unplaceableItems: StaticFlowUnplaceableItem[] = [];
  const fallbackHeight = hasAvailableHeight
    ? measuredAvailableHeight
    : heights.reduce((sum, height) => sum + height, 0) +
      Object.values(headerGroupHeights).reduce((sum, height) => sum + height, 0);

  if (!hasAvailableHeight) {
    options.onZeroHeight?.();
  }

  const finalChunks: StaticFlowChunk[] = distributeFlowItems({
    heights,
    keys,
    metas,
    availableHeight: fallbackHeight,
    headerGroupKeys,
    headerGroupHeights,
    headerGroupRepeats,
    onUnplaceableItem: (item: StaticFlowUnplaceableItem) => {
      unplaceableItems.push(item);
      options.onUnplaceableItem?.(item);
    },
  });
  const signature = hashString(JSON.stringify({
    version: 2,
    flowId,
    availableHeight: Math.round(fallbackHeight * 100) / 100,
    heights: heights.map((height) => Math.round(height * 100) / 100),
    keys,
    metas,
    headerGroupKeys,
    headerGroupHeights,
    headerGroupRepeats,
    unplaceableItems,
  }));

  return { flowId, chunks: finalChunks, signature, unplaceableItems };
}

export function FlowArea({
  children,
  className = '',
  style,
  onFlowMeasurement,
}: FlowAreaProps) {
  const context = React.useContext(StaticFlowContext);
  const areaRef = React.useRef<HTMLDivElement>(null);
  const lastSignatureRef = React.useRef<string>('');
  const warnedMultipleFlowsRef = React.useRef(false);
  const warnedZeroHeightRef = React.useRef(false);
  const warnedUnplaceableItemsRef = React.useRef(new Set<string>());

  useIsoLayoutEffect(() => {
    if (context?.mode !== 'measure' || !context.registerMeasurement || !areaRef.current) {
      return;
    }

    const area = areaRef.current;
    let rafId = 0;
    let resizeObserver: ResizeObserver | null = null;
    lastSignatureRef.current = '';

    const scheduleMeasure = () => {
      window.cancelAnimationFrame(rafId);
      rafId = window.requestAnimationFrame(measure);
    };

    const observedItems = new Set<HTMLElement>();
    const observeFlowItems = () => {
      if (!resizeObserver) return;

      for (const item of Array.from(observedItems)) {
        if (!area.contains(item)) {
          resizeObserver.unobserve(item);
          observedItems.delete(item);
        }
      }

      area
        .querySelectorAll<HTMLElement>('[data-uhuu-flow-item="true"]')
        .forEach((item) => {
          if (observedItems.has(item)) return;
          observedItems.add(item);
          resizeObserver?.observe(item);
        });
    };

    const measure = () => {
      observeFlowItems();

      const flows = area.querySelectorAll<HTMLElement>('[data-uhuu-flow="true"]');
      if (flows.length > 1 && !warnedMultipleFlowsRef.current && isDev()) {
        warnedMultipleFlowsRef.current = true;
        console.warn(
          '[uhuu-components] Static.FlowArea supports one Static.Flow child. ' +
          'Additional Static.Flow elements in the same area are ignored. Use one FlowArea per flow region.'
        );
      }

      const flow = flows[0];
      if (!flow) return;

      const measurement = buildChunks(area, flow, {
        onZeroHeight: () => {
          if (warnedZeroHeightRef.current || !isDev()) return;
          warnedZeroHeightRef.current = true;
          console.warn(
            '[uhuu-components] Static.FlowArea has flow items but no measurable height. ' +
            'Give the area an explicit height or use a constrained flex layout such as flex-1 min-h-0.'
          );
        },
        onUnplaceableItem: (item) => {
          if (warnedUnplaceableItemsRef.current.has(item.key) || !isDev()) return;
          warnedUnplaceableItemsRef.current.add(item.key);
          console.warn(
            `[uhuu-components] Static.Flow item "${item.key}" cannot fit in its FlowArea ` +
            `(${Math.round(item.requiredHeight)}px required > ${Math.round(item.availableHeight)}px available). ` +
            'It is rendered as a controlled flow error instead of clipped content.'
          );
        },
      });
      if (!measurement || measurement.signature === lastSignatureRef.current) return;

      lastSignatureRef.current = measurement.signature;
      onFlowMeasurement?.(measurement);
      context.registerMeasurement?.(measurement);
    };

    resizeObserver = new ResizeObserver(scheduleMeasure);
    resizeObserver.observe(area);
    observeFlowItems();
    scheduleMeasure();

    const mutationObserver = new MutationObserver(() => {
      observeFlowItems();
      scheduleMeasure();
    });
    mutationObserver.observe(area, {
      attributes: true,
      attributeFilter: [
        'class',
        'style',
        'data-uhuu-flow',
        'data-uhuu-flow-id',
        'data-uhuu-flow-item',
        'data-uhuu-flow-key',
        'data-uhuu-flow-break-before',
        'data-uhuu-flow-break-after',
        'data-uhuu-flow-keep-with-next',
        'data-uhuu-flow-avoid-break-inside',
        'data-uhuu-flow-group-key',
        'data-uhuu-flow-header-group-key',
        'data-uhuu-flow-header-repeat',
        'data-uhuu-flow-group-header',
      ],
      characterData: true,
      childList: true,
      subtree: true,
    });

    return () => {
      window.cancelAnimationFrame(rafId);
      resizeObserver?.disconnect();
      mutationObserver.disconnect();
    };
  }, [context, onFlowMeasurement]);

  return (
    <div ref={areaRef} className={className} style={style} data-uhuu-flow-area="true">
      {children}
    </div>
  );
}

type FlowPageProps = {
  children: React.ReactNode;
  header?: React.ReactNode;
  footer?: React.ReactNode;
  className?: string;
  style?: React.CSSProperties;
  flowAreaClassName?: string;
  flowAreaStyle?: React.CSSProperties;
  onFlowMeasurement?: (measurement: StaticFlowMeasurement) => void;
};

export function FlowPage({
  children,
  header,
  footer,
  className = '',
  style,
  flowAreaClassName = '',
  flowAreaStyle,
  onFlowMeasurement,
}: FlowPageProps) {
  return (
    <div
      className={`h-full w-full flex flex-col ${className}`}
      style={style}
      data-uhuu-flow-page="true"
    >
      {header}
      <FlowArea
        className={`flex-1 min-h-0 ${flowAreaClassName}`}
        style={flowAreaStyle}
        onFlowMeasurement={onFlowMeasurement}
      >
        {children}
      </FlowArea>
      {footer}
    </div>
  );
}

function normalizeItemGroup(
  value: StaticFlowItemGroup | string | null | undefined
): StaticFlowItemGroup | undefined {
  if (typeof value === 'string') {
    return value ? { key: value, repeatHeader: true } : undefined;
  }

  if (!value?.key) return undefined;
  return {
    key: value.key,
    repeatHeader: value.repeatHeader !== false,
  };
}

type FlowProps<TItem, TType extends string = DefaultFlowItemType<TItem>> = {
  id: string;
  items: TItem[];
  getKey: (item: TItem, index: number) => React.Key;
  /** The third argument describes this item's visible virtual-page fragment. */
  renderItem: (
    item: TItem,
    index: number,
    fragment: StaticFlowFragmentContext<TItem>
  ) => React.ReactNode;
  getItemMeta?: (item: TItem, index: number) => StaticFlowItemMeta | undefined;
  metaDefaults?: Partial<Record<TType, StaticFlowItemMeta>>;
  getItemType?: (item: TItem, index: number) => TType | undefined;
  /** Opt into a separately measured, repeatable group header. */
  getItemGroup?: (
    item: TItem,
    index: number
  ) => StaticFlowItemGroup | string | null | undefined;
  renderGroupHeader?: (
    group: StaticFlowItemGroup,
    fragment: StaticFlowFragmentContext<TItem>
  ) => React.ReactNode;
  className?: string;
  itemClassName?: string | ((item: TItem, index: number) => string | undefined);
  groupHeaderClassName?: string | ((
    group: StaticFlowItemGroup,
    fragment: StaticFlowFragmentContext<TItem>
  ) => string | undefined);
  renderUnplaceableItem?: (
    item: StaticFlowUnplaceableItem,
    context: StaticFlowUnplaceableContext
  ) => React.ReactNode;
};

export function Flow<TItem, TType extends string = DefaultFlowItemType<TItem>>({
  id,
  items,
  getKey,
  renderItem,
  getItemMeta,
  metaDefaults,
  getItemType: resolveItemType,
  getItemGroup,
  renderGroupHeader,
  className = '',
  itemClassName,
  groupHeaderClassName,
  renderUnplaceableItem,
}: FlowProps<TItem, TType>) {
  const context = React.useContext(StaticFlowContext);
  const chunks = context?.chunksByFlowId?.[id];
  const activeChunk = context?.mode === 'visible' && chunks
    ? chunks[context.pageIndex]
    : undefined;
  const rawVisibleIndexes =
    context?.mode === 'visible' && chunks
      ? (activeChunk?.indexes ?? [])
      : context?.mode === 'visible' && context.pageIndex > 0
        ? []
        : items.map((_, index) => index);

  // Guard against stale chunk indexes when items shrink (e.g. rowCount decreased before remeasure)
  const visibleIndexes = rawVisibleIndexes.filter((idx) => (
    Number.isInteger(idx) && idx >= 0 && idx < items.length
  ));
  const itemGroups = items.map((item, index) => normalizeItemGroup(getItemGroup?.(item, index)));
  const pageIndex = context?.mode === 'visible' ? context.pageIndex : 0;
  const pageCount = context?.mode === 'visible' && chunks ? chunks.length : 1;

  React.useEffect(() => {
    if (!isDev() || !metaDefaults || !Object.keys(metaDefaults).length || !items.length) {
      return;
    }

    const warningKey = `${id}:${Object.keys(metaDefaults).join('|')}`;
    if (warnedMetaDefaultsWithoutType.has(warningKey)) return;

    const hasResolvableType = items.some((item, index) => (
      Boolean(resolveItemType?.(item, index) ?? getItemType(item))
    ));
    if (hasResolvableType) return;

    warnedMetaDefaultsWithoutType.add(warningKey);
    console.warn(
      `[uhuu-components] Static.Flow "${id}" received metaDefaults, but no item type could be resolved. ` +
      'Add a type field to each item or pass getItemType so defaults can be applied.'
    );
  }, [id, items, metaDefaults, resolveItemType]);

  return (
    <div
      className={className}
      data-uhuu-flow="true"
      data-uhuu-flow-id={id}
    >
      {activeChunk?.unplaceable && (
        renderUnplaceableItem?.(activeChunk.unplaceable, { flowId: id, pageIndex, pageCount }) ?? (
          <div
            role="alert"
            className="uhuu-flow-unplaceable"
            data-uhuu-flow-unplaceable="true"
            data-uhuu-flow-unplaceable-key={activeChunk.unplaceable.key}
          >
            Unable to fit “{activeChunk.unplaceable.key}” on a page. Reduce its height or split it.
          </div>
        )
      )}
      {visibleIndexes.map((itemIndex) => {
        const item = items[itemIndex];
        if (item === undefined) return null;

        const key = getKey(item, itemIndex);
        const group = itemGroups[itemIndex];
        const coreFragment = getFlowFragmentState({
          itemIndex,
          fragmentIndexes: visibleIndexes,
          groupKeys: itemGroups.map((entry) => entry?.key),
          pageIndex,
          pageCount,
          itemCount: items.length,
        });
        const fragment: StaticFlowFragmentContext<TItem> = {
          ...coreFragment,
          flowId: id,
          itemKey: key,
          item,
        };
        const type = resolveItemType?.(item, itemIndex) ?? (getItemType(item) as TType | undefined);
        const meta = mergeItemMeta(
          type ? metaDefaults?.[type] : undefined,
          getItemMeta?.(item, itemIndex)
        );
        const resolvedItemClassName =
          typeof itemClassName === 'function'
            ? itemClassName(item, itemIndex)
            : itemClassName;
        const plannedGroupHeader = activeChunk?.groupHeaders?.find((header) => (
          header.itemIndex === itemIndex && header.groupKey === group?.key
        ));
        const shouldRenderGroupHeader = Boolean(
          group &&
          renderGroupHeader &&
          (
            plannedGroupHeader || (
              !activeChunk?.groupHeaders &&
              fragment.isFirstInGroupOnPage &&
              (fragment.isFirstInGroup || group.repeatHeader !== false)
            )
          )
        );
        const resolvedGroupHeaderClassName: string | undefined =
          typeof groupHeaderClassName === 'function'
            ? (group ? groupHeaderClassName(group, fragment) : undefined)
            : groupHeaderClassName;

        return (
          <React.Fragment key={key}>
            {shouldRenderGroupHeader && group && (
              <div
                className={resolvedGroupHeaderClassName}
                style={{ display: 'flow-root' }}
                data-uhuu-flow-group-header="true"
                data-uhuu-flow-header-group-key={group.key}
              >
                {renderGroupHeader?.(group, fragment)}
              </div>
            )}
            <div
              className={resolvedItemClassName}
              style={{ display: 'flow-root' }}
              data-uhuu-flow-item="true"
              data-uhuu-flow-key={String(key)}
              data-uhuu-flow-index={itemIndex}
              data-uhuu-flow-break-before={meta.breakBefore ? 'true' : undefined}
              data-uhuu-flow-break-after={meta.breakAfter ? 'true' : undefined}
              data-uhuu-flow-keep-with-next={serializeKeepWithNext(meta.keepWithNext)}
              data-uhuu-flow-avoid-break-inside={meta.avoidBreakInside ? 'true' : undefined}
              data-uhuu-flow-group-key={meta.groupKey}
              data-uhuu-flow-header-group-key={group?.key}
              data-uhuu-flow-header-repeat={group ? (group.repeatHeader === false ? 'false' : 'true') : undefined}
            >
              {renderItem(item, itemIndex, fragment)}
            </div>
          </React.Fragment>
        );
      })}
    </div>
  );
}
