export function createVirtualFlowPages(logicalPages = [], flowLayoutsByPageKey = {}) {
  const pages = [];
  let nextPageNum = 1;

  for (const page of logicalPages) {
    const flowLayout = page.hasFlow ? flowLayoutsByPageKey[page.flowKey] : undefined;
    const flowChunkSets = Object.values(flowLayout?.flows ?? {});
    const virtualPageCount = Math.max(1, ...flowChunkSets.map((chunks) => chunks.length));

    for (let virtualPageIndex = 0; virtualPageIndex < virtualPageCount; virtualPageIndex += 1) {
      pages.push({
        ...page,
        pageNum: nextPageNum++,
        virtualPageId: virtualPageIndex === 0
          ? page.id
          : `${page.id}__flow_${virtualPageIndex + 1}`,
        virtualPageIndex,
        virtualPageCount,
        flowChunksByFlowId: flowLayout?.flows,
      });
    }
  }

  return pages;
}
