// Shared id/slug helpers for flow-item adapters (markdown-flow, html-flow).
// Keeping these in one place guarantees markdownToFlowItems and htmlToFlowItems
// produce identical, stable ids for equivalent content.

export function slugify(value) {
  return String(value ?? '')
    .replace(/[#*_`|>[\]()]/g, '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 36);
}

export function blockId(type, source, index, idPrefix = '') {
  const slug = slugify(source);
  return `${idPrefix}${type}-${index}-${slug || 'block'}`;
}
