import { useCallback, useMemo, useState } from 'react';
import type { StaticFlowChunk, StaticFlowMeasurement } from '../../pagination-static/flow-static';
import type { PageFilterConfig, PageItem, StandalonePage } from './page-group-utils';
import { isPageNumberIncludedInFilter } from './page-group-utils';
import { createVirtualFlowPages } from './flow-layout-core';

type PageFlowLayout = {
  flows: Record<string, StaticFlowChunk[]>;
};

type FlowLayoutsByPageKey = Record<string, PageFlowLayout>;

type FlowLayoutState = {
  layoutKey: string;
  layouts: FlowLayoutsByPageKey;
};

export type LogicalFlowPage = (StandalonePage & { pageNum: number }) & {
  parentGroup?: PageItem;
  flowKey: string;
  basePageNum: number;
};

export type VirtualFlowPage<TPage extends LogicalFlowPage = LogicalFlowPage> = TPage & {
  pageNum: number;
  virtualPageId: string;
  virtualPageIndex: number;
  virtualPageCount: number;
  flowChunksByFlowId?: Record<string, StaticFlowChunk[]>;
};

type UseFlowLayoutsArgs<TPage extends LogicalFlowPage> = {
  logicalPages: TPage[];
  pageFilter?: PageFilterConfig | null;
  layoutKey?: string;
};

export function useFlowLayouts<TPage extends LogicalFlowPage>({
  logicalPages,
  pageFilter,
  layoutKey = '',
}: UseFlowLayoutsArgs<TPage>) {
  const [flowLayoutState, setFlowLayoutState] = useState<FlowLayoutState>({
    layoutKey,
    layouts: {},
  });
  const flowLayoutsByPageKey = flowLayoutState.layoutKey === layoutKey
    ? flowLayoutState.layouts
    : {};

  const currentFlowPageKeySignature = useMemo(
    () => logicalPages
      .filter((page) => page.hasFlow)
      .map((page) => page.flowKey)
      .join('|'),
    [logicalPages]
  );

  const currentFlowPageKeys = useMemo(
    () => new Set(currentFlowPageKeySignature ? currentFlowPageKeySignature.split('|') : []),
    [currentFlowPageKeySignature]
  );

  const activeFlowLayoutsByPageKey = useMemo(() => {
    const activeLayouts: FlowLayoutsByPageKey = {};

    for (const page of logicalPages) {
      if (!page.hasFlow) continue;
      const layout = flowLayoutsByPageKey[page.flowKey];
      if (layout) activeLayouts[page.flowKey] = layout;
    }

    return activeLayouts;
  }, [flowLayoutsByPageKey, logicalPages]);

  const registerMeasurement = useCallback((
    pageKey: string,
    measurement: StaticFlowMeasurement
  ) => {
    if (!currentFlowPageKeys.has(pageKey)) return;

    setFlowLayoutState((current) => {
      const sourceLayouts = current.layoutKey === layoutKey ? current.layouts : {};
      const currentLayouts: FlowLayoutsByPageKey = {};
      let prunedStaleLayouts = false;

      for (const [key, layout] of Object.entries(sourceLayouts)) {
        if (currentFlowPageKeys.has(key)) {
          currentLayouts[key] = layout;
        } else {
          prunedStaleLayouts = true;
        }
      }

      const currentLayout = currentLayouts[pageKey] ?? { flows: {} };
      const currentChunks = currentLayout.flows[measurement.flowId];
      const currentSignature = currentChunks ? JSON.stringify(currentChunks) : '';
      const nextSignature = JSON.stringify(measurement.chunks);

      if (
        current.layoutKey === layoutKey &&
        currentSignature === nextSignature &&
        !prunedStaleLayouts
      ) {
        return current;
      }

      return {
        layoutKey,
        layouts: {
          ...currentLayouts,
          [pageKey]: {
            flows: {
              ...currentLayout.flows,
              [measurement.flowId]: measurement.chunks,
            },
          },
        },
      };
    });
  }, [currentFlowPageKeys, layoutKey]);

  const allVirtualPages = useMemo<Array<VirtualFlowPage<TPage>>>(
    () => createVirtualFlowPages(logicalPages, activeFlowLayoutsByPageKey) as Array<VirtualFlowPage<TPage>>,
    [logicalPages, activeFlowLayoutsByPageKey]
  );

  const virtualTotalPageCount = allVirtualPages.length;

  const renderedVirtualPages = useMemo(
    () => allVirtualPages.filter((page) => (
      isPageNumberIncludedInFilter(page.pageNum, virtualTotalPageCount, pageFilter)
    )),
    [allVirtualPages, virtualTotalPageCount, pageFilter]
  );

  return {
    allVirtualPages,
    renderedVirtualPages,
    virtualTotalPageCount,
    registerMeasurement,
  };
}
