import { MoreHorizontal } from 'lucide-react';
import { Button } from '../../ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuTrigger,
} from '../../ui/dropdown-menu';
import { PageOption } from './page-editor';
import { PageItem } from './page-group-utils';
import { PageOptionsRenderer, getApplicablePageOptions } from './page-options-renderer';

export interface PageOptionsDropdownProps {
  pageOptions: PageOption[];
  targetItem: PageItem | undefined;
  onChange: (pageOption: PageOption, targetItem: PageItem, value: string) => void;
  title?: string;
  triggerClassName?: string;
}

export function PageOptionsDropdown({
  pageOptions,
  targetItem,
  onChange,
  title = 'Options',
  triggerClassName,
}: PageOptionsDropdownProps) {
  if (!targetItem) return null;
  if (getApplicablePageOptions(pageOptions, targetItem).length === 0) return null;

  return (
    <DropdownMenu modal={false}>
      <DropdownMenuTrigger asChild className={triggerClassName || 'page-options-trigger'}>
        <Button
          variant="ghost"
          size="sm"
          className="h-7 w-7 text-gray-400 hover:text-gray-600 border border-transparent hover:border-gray-200 rounded-md"
          title={title}
        >
          <MoreHorizontal className="w-3.5 h-3.5" />
          <span className="sr-only">{title}</span>
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent className="min-w-48 p-3" align="center">
        <PageOptionsRenderer
          pageOptions={pageOptions}
          targetItem={targetItem}
          onChange={onChange}
        />
      </DropdownMenuContent>
    </DropdownMenu>
  );
}

