function finitePositive(value) {
  return typeof value === 'number' && Number.isFinite(value) && value > 0 ? value : 0;
}

function normalizeGroupKey(value) {
  return typeof value === 'string' && value ? value : null;
}

function getKeepWithNextCount(value) {
  if (typeof value === 'number' && Number.isFinite(value)) {
    return Math.max(0, Math.floor(value));
  }

  return value ? 1 : 0;
}

/**
 * Return the visible-fragment state for one flow item. It stays in the small
 * dependency-free core so the measurement algorithm and React renderer use
 * exactly the same continuation rules.
 */
export function getFlowFragmentState({
  itemIndex = -1,
  fragmentIndexes = [],
  groupKeys = [],
  pageIndex = 0,
  pageCount = 1,
  itemCount = 0,
} = {}) {
  const fragmentIndex = fragmentIndexes.indexOf(itemIndex);
  const groupKey = normalizeGroupKey(groupKeys[itemIndex]);
  const previousFragmentItemIndex = fragmentIndex > 0
    ? fragmentIndexes[fragmentIndex - 1]
    : null;
  const previousFragmentGroupKey = previousFragmentItemIndex === null
    ? null
    : normalizeGroupKey(groupKeys[previousFragmentItemIndex]);
  const previousSourceGroupKey = itemIndex > 0
    ? normalizeGroupKey(groupKeys[itemIndex - 1])
    : null;
  const isFirstInGroup = Boolean(groupKey && previousSourceGroupKey !== groupKey);
  const isFirstInGroupOnPage = Boolean(groupKey && previousFragmentGroupKey !== groupKey);

  return {
    pageIndex,
    pageCount,
    itemIndex,
    fragmentIndex,
    groupKey: groupKey ?? undefined,
    isFirst: itemIndex === 0,
    isLast: itemCount > 0 && itemIndex === itemCount - 1,
    isFirstInFragment: fragmentIndex === 0,
    isLastInFragment: fragmentIndex >= 0 && fragmentIndex === fragmentIndexes.length - 1,
    isFirstInGroup,
    isFirstInGroupOnPage,
    // `isContinuation` refers to the virtual Flow page. `isGroupContinuation`
    // is the narrower signal for a repeated group header.
    isContinuation: pageIndex > 0,
    isGroupContinuation: Boolean(
      isFirstInGroupOnPage && !isFirstInGroup && previousSourceGroupKey === groupKey
    ),
  };
}

/**
 * Split measured Flow items into virtual-page chunks. `headerGroupKeys` is
 * intentionally separate from item metadata's `groupKey`: existing callers
 * can keep using `groupKey` for avoid-break groups without opting into a
 * repeated measured header.
 */
export function distributeFlowItems({
  heights = [],
  keys = [],
  metas = [],
  availableHeight = 0,
  headerGroupKeys = [],
  headerGroupHeights = {},
  headerGroupRepeats = {},
  onUnplaceableItem,
} = {}) {
  const normalizedAvailableHeight = finitePositive(availableHeight) || Number.POSITIVE_INFINITY;
  const chunks = [{ indexes: [], keys: [] }];
  let currentHeight = 0;

  const currentChunk = () => chunks[chunks.length - 1];
  const currentLastIndex = () => {
    const indexes = currentChunk().indexes;
    return indexes.length ? indexes[indexes.length - 1] : null;
  };
  const currentHasContent = () => (
    currentChunk().indexes.length > 0 || Boolean(currentChunk().unplaceable)
  );

  const getHeaderGroupKey = (index) => normalizeGroupKey(headerGroupKeys[index]);
  const getHeaderHeight = (groupKey) => finitePositive(headerGroupHeights[groupKey] ?? 0);
  const shouldRepeatHeader = (groupKey) => headerGroupRepeats[groupKey] !== false;
  const needsGroupHeader = (index, previousIndex) => {
    const groupKey = getHeaderGroupKey(index);
    if (!groupKey) return false;

    if (previousIndex === null || previousIndex === undefined) {
      const previousSourceGroupKey = index > 0 ? getHeaderGroupKey(index - 1) : null;
      return previousSourceGroupKey !== groupKey || shouldRepeatHeader(groupKey);
    }

    return getHeaderGroupKey(previousIndex) !== groupKey;
  };
  const getItemHeightWithHeader = (index, previousIndex) => {
    const groupKey = getHeaderGroupKey(index);
    return finitePositive(heights[index]) + (
      groupKey && needsGroupHeader(index, previousIndex) ? getHeaderHeight(groupKey) : 0
    );
  };

  const getAvoidBreakGroupKey = (index) => {
    const meta = metas[index] ?? {};
    return meta.avoidBreakInside && meta.groupKey ? meta.groupKey : null;
  };

  const getAvoidBreakGroupHeight = (startIndex, groupKey, previousIndex) => {
    let height = 0;
    let priorIndex = previousIndex;

    for (let index = startIndex; index < heights.length; index += 1) {
      if (getAvoidBreakGroupKey(index) !== groupKey) break;
      height += getItemHeightWithHeader(index, priorIndex);
      priorIndex = index;
    }

    return height;
  };

  const getKeepWithNextHeight = (index, count) => {
    let height = 0;
    let priorIndex = index;

    for (let offset = 1; offset <= count; offset += 1) {
      const nextIndex = index + offset;
      if (nextIndex >= heights.length) break;
      height += getItemHeightWithHeader(nextIndex, priorIndex);
      priorIndex = nextIndex;
    }

    return height;
  };

  const startNextChunk = () => {
    if (currentHasContent()) {
      chunks.push({ indexes: [], keys: [] });
      currentHeight = 0;
    }
  };

  const addUnplaceableItem = (index, height, requiredHeight) => {
    const key = keys[index] ?? String(index);
    const groupKey = getHeaderGroupKey(index) ?? undefined;
    const headerHeight = groupKey && needsGroupHeader(index, null)
      ? getHeaderHeight(groupKey)
      : 0;
    const unplaceable = {
      index,
      key,
      height,
      headerHeight,
      requiredHeight,
      availableHeight: normalizedAvailableHeight,
      groupKey,
      reason: headerHeight > 0 ? 'item-with-header-too-tall' : 'item-too-tall',
    };

    // A discrete error chunk is deliberate: it keeps virtual-page expansion
    // finite and makes the failure visible instead of rendering clipped content.
    currentChunk().unplaceable = unplaceable;
    onUnplaceableItem?.(unplaceable);
    chunks.push({ indexes: [], keys: [] });
    currentHeight = 0;
  };

  for (let index = 0; index < heights.length; index += 1) {
    const meta = metas[index] ?? {};
    const height = finitePositive(heights[index]);
    const key = keys[index] ?? String(index);

    if (meta.breakBefore) {
      startNextChunk();
    }

    const avoidBreakGroupKey = getAvoidBreakGroupKey(index);
    const previousAvoidBreakGroupKey = index > 0 ? getAvoidBreakGroupKey(index - 1) : null;
    if (
      avoidBreakGroupKey &&
      avoidBreakGroupKey !== previousAvoidBreakGroupKey &&
      currentHasContent() &&
      currentHeight + getAvoidBreakGroupHeight(index, avoidBreakGroupKey, currentLastIndex()) > normalizedAvailableHeight
    ) {
      // If the group cannot fit on an empty page we intentionally fall through
      // to normal row-level continuation below instead of creating a blank page.
      startNextChunk();
    }

    let previousIndex = currentLastIndex();
    let ownHeight = getItemHeightWithHeader(index, previousIndex);

    // A page boundary can add a repeated group header. Recalculate after moving
    // so a row is never admitted based on the previous page's header state.
    if (currentHasContent() && ownHeight > normalizedAvailableHeight - currentHeight) {
      startNextChunk();
      previousIndex = null;
      ownHeight = getItemHeightWithHeader(index, previousIndex);
    }

    if (ownHeight > normalizedAvailableHeight) {
      addUnplaceableItem(index, height, ownHeight);
      continue;
    }

    const requiredHeight = ownHeight + getKeepWithNextHeight(
      index,
      getKeepWithNextCount(meta.keepWithNext)
    );
    if (currentHasContent() && currentHeight + requiredHeight > normalizedAvailableHeight) {
      startNextChunk();
      previousIndex = null;
      ownHeight = getItemHeightWithHeader(index, previousIndex);

      if (ownHeight > normalizedAvailableHeight) {
        addUnplaceableItem(index, height, ownHeight);
        continue;
      }
    }

    currentChunk().indexes.push(index);
    currentChunk().keys.push(key);
    currentHeight += ownHeight;

    if (meta.breakAfter && index < heights.length - 1) {
      startNextChunk();
    }
  }

  const populatedChunks = chunks.filter((chunk) => (
    chunk.indexes.length > 0 || Boolean(chunk.unplaceable)
  ));
  if (!populatedChunks.length) return [{ indexes: [], keys: [] }];

  return populatedChunks.map((chunk) => {
    if (!chunk.indexes.length) return chunk;

    const groupHeaders = [];
    for (let position = 0; position < chunk.indexes.length; position += 1) {
      const itemIndex = chunk.indexes[position];
      const groupKey = getHeaderGroupKey(itemIndex);
      const previousIndex = position > 0 ? chunk.indexes[position - 1] : null;
      if (!groupKey || !needsGroupHeader(itemIndex, previousIndex)) continue;

      const previousSourceGroupKey = itemIndex > 0 ? getHeaderGroupKey(itemIndex - 1) : null;
      groupHeaders.push({
        groupKey,
        itemIndex,
        isContinuation: previousSourceGroupKey === groupKey,
      });
    }

    return groupHeaders.length ? { ...chunk, groupHeaders } : chunk;
  });
}
